import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is IRR?", a: "IRR, or internal rate of return, is the discount rate that makes an investment's net present value equal zero." },
  { q: "How do you calculate IRR?", a: "IRR is usually found by iteration, testing discount rates until the present value of future cash flows equals the initial investment." },
  { q: "What is the difference between IRR and NPV?", a: "NPV gives a dollar value at a chosen discount rate, while IRR gives the return rate implied by the cash flows." },
  { q: "What is a good IRR?", a: "A good IRR is usually above the required return or hurdle rate for the risk level of the project." },
  { q: "What is the hurdle rate?", a: "The hurdle rate is the minimum return an investor requires before accepting an investment." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const pct = (v: number) => `${Number.isFinite(v) ? v.toFixed(2) : "0.00"}%`;
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
const npv = (initial: number, flows: number[], rate: number) => -initial + flows.reduce((sum, cf, i) => sum + cf / Math.pow(1 + rate, i + 1), 0);
function irr(initial: number, flows: number[]) {
  let low = -0.99, high = 10;
  for (let i = 0; i < 100; i++) { const mid = (low + high) / 2; if (npv(initial, flows, mid) > 0) low = mid; else high = mid; }
  return (low + high) / 2;
}
function payback(initial: number, flows: number[]) {
  let remaining = initial;
  for (let i = 0; i < flows.length; i++) {
    if (flows[i] >= remaining) return i + remaining / flows[i];
    remaining -= flows[i];
  }
  return 0;
}

export default function IRRCalculator() {
  useCurrencyVersion();
  const [initial, setInitial] = useState(50000);
  const [discountRate, setDiscountRate] = useState(10);
  const [cashFlows, setCashFlows] = useState("8000, 9000, 11000, 14000, 18000, 22000");
  const flows = useMemo(() => cashFlows.split(",").map((x) => Number(x.trim())).filter(Number.isFinite).slice(0, 10), [cashFlows]);
  const result = useMemo(() => { const rate = irr(initial, flows); return { irr: rate * 100, npv: npv(initial, flows, discountRate / 100), payback: payback(initial, flows) }; }, [initial, flows, discountRate]);
  const guide = [
    ["IRR below hurdle rate", "10%", "Negative", "Reject or revise", "High"],
    ["IRR equal to hurdle rate", "10%", "Near zero", "Indifferent", "Moderate"],
    ["IRR slightly above hurdle rate", "10%", "Positive", "Consider", "Moderate"],
    ["IRR well above hurdle rate", "10%", "Strong positive", "Attractive", "Lower cushion risk"],
  ];
  return (
    <>
      <SEOHead title="Free IRR Calculator Online - Calculate Internal Rate of Return Instantly | CalcHive" description="Free online IRR calculator. Calculate internal rate of return, net present value and payback period for any investment cash flows instantly. 100% free, no signup required." canonical="/irr-calculator" keywords="free IRR calculator, internal rate of return calculator free online, NPV IRR calculator free, calculate IRR free, investment return rate calculator free" category="Financial Calculators" breadcrumbName="Free IRR Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free IRR Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Calculate internal rate of return, NPV, and payback period from investment cash flows.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Initial investment</label><input type="number" value={initial} onChange={(e) => setInitial(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">NPV discount rate (%)</label><input type="number" value={discountRate} onChange={(e) => setDiscountRate(Number(e.target.value))} className={inputClass} /></div><div className="sm:col-span-2"><label className="text-sm font-semibold text-foreground block mb-2">Annual cash flows, separated by commas</label><input value={cashFlows} onChange={(e) => setCashFlows(e.target.value)} className={inputClass} /></div></div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Internal Rate of Return</p><p className="text-5xl sm:text-6xl font-black text-white">{pct(result.irr)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">NPV</p><p className="text-lg font-extrabold text-foreground">{money(result.npv)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Payback period</p><p className="text-lg font-extrabold text-foreground">{result.payback ? `${result.payback.toFixed(2)} years` : "Not reached"}</p></div></div>
          <div className="overflow-x-auto mt-5"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">Cash Flow and NPV Table</caption><thead className="bg-muted/60"><tr>{["Year", "Cash Flow", "Present Value"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{flows.map((cf, i) => <tr key={i}><td className="py-2.5 px-3">{i + 1}</td><td className="py-2.5 px-3">{money(cf)}</td><td className="py-2.5 px-3">{money(cf / Math.pow(1 + discountRate / 100, i + 1))}</td></tr>)}</tbody></table></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate Internal Rate of Return for Free</h2><p className="text-muted-foreground leading-relaxed">IRR finds the rate where discounted future cash flows equal the initial investment.</p><h2 className="text-2xl font-bold text-foreground">How IRR and NPV Are Used in Investment Decisions</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">IRR vs Required Return - Investment Decision Guide</caption><thead className="bg-muted/60"><tr>{["Project IRR", "Required Return (hurdle rate)", "NPV Result", "Investment Decision", "Risk Level"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{guide.map((row) => <tr key={row[0]}>{row.map((cell) => <td key={cell} className="py-2.5 px-3">{cell}</td>)}</tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free IRR and NPV Calculator for Investors and Students</h2><p className="text-muted-foreground leading-relaxed">Use IRR together with NPV, payback, risk, and cash-flow confidence before making an investment decision.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/irr-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


